import pytest
import requests

def test_expired_session_api_request_returns_401(
    expired_token_fixture,
    base_url,
):
    expired_token = expired_token_fixture
    headers = {"Authorization": f"Bearer {expired_token}"}
    resp = requests.get(
        f"{base_url}/api/profile",
        headers=headers,
        allow_redirects=False,
    )
    assert resp.status_code == 401, (
        f"Expected 401 for expired session, got {resp.status_code}"
    )
    body = resp.json() if resp.content else {}
    assert "data" not in body or body.get("data") is None, (
        "No protected data should be returned on 401"
    )
    error_msg = str(body).lower()
    assert any(k in error_msg for k in ["expired", "unauthorized", "invalid", "unauthenticated"]), (
        f"Expected expiry/auth error in body, got: {body}"
    )
